def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 12):
                part1 = np.tanh(ratio * a) * (a ** 3)
                part2 = np.cos(ratio * a * np.pi) * (a ** 1.8)
                if a % 4 == 0:
                    part1 *= 0.92
                else:
                    part2 *= 1.08
                score += part1 + part2
            if (capacity + item) % 4 == 0 and (capacity - item) % 6 == 0:
                score *= 0.82
            score = np.log1p(score + 5)
        elif 0.05 <= ratio < 0.2:
            product = 1
            sum_val = 0
            limit = int(capacity) if capacity < 20 else 20
            for n in range(1, limit + 3):
                term = (ratio + np.sin(n)) * (n / (n + 2))
                product *= term if term > 0 else 1
                sum_val += np.abs(np.cos(ratio * n))
                if product > 5e6:
                    product = np.sqrt(product)
                if sum_val > 500:
                    sum_val = np.log1p(sum_val)
            mod_val = int(product + sum_val) % 350
            score += np.sqrt(ratio * mod_val + 3) + sum_val / 10
            if (int(capacity) % 5 == 0) ^ ((item * 5) % 4 == 0):
                score += 6.3
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                fract = ((ratio * x**3) % 1) * (x ** 2.3)
                extra_sum += fract if fract < 0.7 else fract / 1.5
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                exp_term = np.exp(-(m + ratio))
                increment = (ratio ** (m + 1)) * (m ** 3.1) / ((m + 1) ** 1.1) * exp_term
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 9 + remainder * 0.65
                if remainder < 1:
                    score += 5
            else:
                score -= remainder * 1.1
            if score < -8:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 8 == 0:
                score *= 1.35
            if score > 20:
                score /= 2.5
            if np.isclose(ratio, 0.4, atol=0.02):
                score += 3.7
        elif 0.5 < ratio <= 0.75:
            penalty = 0
            for p in range(1, 13):
                penalty += ((ratio - 0.5) ** p) * (p ** 1.8) / (p + 0.5)
                if penalty > 70:
                    penalty = np.log1p(penalty)
                    break
            score = penalty * 15
            if capacity < item * 1.15:
                score += 12
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 6 == 0):
                score -= 8
            if score < 0:
                score = abs(score) * 1.3 + 6
            if score > 130:
                score = 130
        elif 0.75 < ratio <= 1.2:
            extra_penalty = 0
            diff = ratio - 0.75
            for q in range(1, 14):
                extra_penalty += ((diff) ** q) * (q ** 2.8) / (q + 0.3)
                if extra_penalty > 1500:
                    extra_penalty = np.sqrt(extra_penalty)
                    break
            score = extra_penalty * 18
            if capacity < item * 1.45:
                score += 22
            if (int(capacity * 2) % 7 == 0) and (int(item * 11) % 5 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.3)) % 1) * (z * 1.9)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
        elif 1.2 < ratio <= 1.7:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term)
                super_penalty += np.log1p(term)
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 14) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(1, 9):
                score += ((diff / (w + 0.7)) % 1) * (w * 2.3)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        else:
            mega_penalty = 0
            diff = ratio - 1.7
            for s in range(1, 20):
                val = np.tanh(diff * s) * (s ** 3.8) * (diff ** 2)
                if val > 20000:
                    val = np.log1p(val)
                mega_penalty += val
            score = mega_penalty * 40
            if capacity < item * 3:
                score += 40
            if (int(capacity * 17) % 6 == 0) and (int(item * 23) % 7 == 0):
                score -= 15
            for u in range(1, 11):
                score += ((diff / (u + 1.1)) % 1) * (u * 2.8)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            if ratio > 1.5:
                score *= 0.85
        elif capacity < 3:
            score *= 2.8
            if ratio < 0.2:
                score *= 1.15
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        if i % 2 == 0:
            score *= 1 + (np.sin(ratio * np.pi) / 10)
        else:
            score *= 1 - (np.cos(ratio * np.pi) / 12)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = (np.max(finite_priorities) + np.mean(finite_priorities)) * (12 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
